#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y,z;
    int cnt,ans;
}a[100010],b[100010];
int lowbit(int x)
{
    return x&-x;
}
int sum[500010];
long long ans[100010],n,k,tot;
void update(int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
int query(int x)
{
    if(x<0)
    {
        x=0;
    }
    if(x>n)
    {
        x=n;
    }
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
bool cmpx(node a,node b)
{
    return a.x<b.x;
}
bool cmpy(node a,node b)
{
    return a.y>b.y;
}
void cdq(int l,int r)
{
    if(l==r)
    {
        return;
    }
    int mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    sort(a+l,a+1+mid,cmpy);
    sort(a+mid+1,a+1+r,cmpy);
    int i=l,j=mid+1;
    while(j<=r)
    {
        while(i<=mid&&a[i].y>a[j].y)
        {
            update(a[i].z,1);
            i++;
        }
        a[j].ans+=query(n)-query(a[j].z+k)+query(a[j].z-k-1);
        j++;
    }
    for(int k=l;k<i;k++)
    {
        update(a[k].z,-1);
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        a[i].z=i;
        int x;
        scanf("%d",&x);
        a[x].x=i;
    }
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        a[x].y=i;
    }
    sort(a+1,a+1+n,cmpx);
    cdq(1,n);
    long long res=0;
    for(int i=1;i<=n;i++)
    {
        res+=a[i].ans;
    }
    printf("%lld",res);
    return 0;
}
